{"type": "email", "id": "email_001", "subject": "Canada's Revised ZEV Mandate and Compliance Documentation Update", "from": "rachel.kim@elexionauto.com", "from_name": "Rachel Kim", "to": ["mark.johnson@elexionauto.com"], "cc": ["linda.miller@elexionauto.com", "peter.wright@elexionauto.com"], "date": "2026-01-05 09:00:00", "body": "Dear Mark,

